'use strict';
// Gulp-free browserify build for @be/doom (same approach as build-recipe.js).
const path = require('path');
const fs = require('fs');
const browserify = require('browserify');
const tsify = require('tsify-preprocess');
const mapstraction = require('mapstraction');
const BrowserifyTransform = require('./browserify-transform');

const skillDir = process.argv[2];
if (!skillDir) {
  console.error('usage: node build-doom.js <absolute-skill-dir>');
  process.exit(1);
}
process.chdir(skillDir);

const options = {
  app: path.join(skillDir, 'src', 'index.ts'),
  bundle: 'index.js',
  map: 'index.js.map',
  name: 'bedoom',
  standalone: true
};

const prod = false;

const bundler = browserify({
  entries: options.app,
  bundleExternal: false,
  debug: !prod,
  builtins: false,
  extensions: ['.bt', '.flow'],
  cache: {},
  packageCache: {},
  standalone: options.standalone ? options.name : undefined
});

bundler.plugin(tsify, {
  removeComments: true,
  target: 'es6',
  preprocess: {
    DEBUG: !prod,
    RELEASE: !!prod,
    PARTNER: false,
    INTERNAL: true
  }
});

bundler.plugin(mapstraction, { _: [options.map] });
bundler.transform(BrowserifyTransform.default || BrowserifyTransform);

bundler.on('log', (m) => console.log('[browserify]', m));

bundler.bundle()
  .on('error', (err) => {
    console.error('BUILD ERROR:\n', err && err.message ? err.message : err);
    process.exit(1);
  })
  .pipe(fs.createWriteStream(path.join(skillDir, options.bundle)))
  .on('finish', () => console.log('WROTE', path.join(skillDir, options.bundle)));
